364	    impl SpanVecExt for Vec<Span<Token>> {
365	        fn to_strings(&self, doc: &Document) -> Vec<String> {
366	            self.iter()
367	                .map(|sp| {
368	                    doc.get_tokens()[sp.start..sp.end]
369	                        .iter()
370	                        .map(|tok| doc.get_span_content_str(&tok.span))
371	                        .collect::<String>()
