            "I want to try this instead of that.",
        );
    }

    #[test]
    fn split_common() {
        assert_suggestion_result(
            "This is notnot a problem.",
            SplitWords::default(),
            "This is not not a problem.",
        );
    }

    #[test]
    fn splits_multiple_compound_words() {
        assert_suggestion_result(
            "We stared intothe darkness and kindof panicked about sortof everything.",
            SplitWords::default(),
            "We stared into the darkness and kind of panicked about sort of everything.",
        );
    }

    #[test]
    fn splits_word_with_longer_prefix() {
        assert_suggestion_result(
            "The astronauts waited on the landingpad for hours.",
            SplitWords::default(),
            "The astronauts waited on the landing pad for hours.",
        );
    }

    #[test]
    fn splits_before_punctuation() {
        assert_suggestion_result(
            "This was kindof, actually, hilarious.",
            SplitWords::default(),
            "This was kind of, actually, hilarious.",
        );
    }

    #[test]
    fn ignores_known_compound_words() {
        assert_no_lints("Someone left early.", SplitWords::default());
    }

    #[test]
    fn ignores_prefix_without_valid_remainder() {
        assert_no_lints("The monkeyxyz escaped unnoticed.", SplitWords::default());
    }

    #[test]
    fn test_atall_to_at_all() {
        assert_suggestion_result(
            "don't seem to support symbolic links atall.",
            SplitWords::default(),
            "don't seem to support symbolic links at all.",
        );
    }

    #[test]
    fn test_atall_to_a_tall() {
        assert_suggestion_result("atall", SplitWords::default(), "a tall");
    }

    #[test]
    fn atall_should_split_to_a_tall_and_at_all() {
        assert_good_and_bad_suggestions("atall", SplitWords::default(), &["a tall", "at all"], &[]);
    }

    #[test]
    fn issue_2763_leaves() {
        assert_suggestion_result(
            "I love to eat cornleaves.",
            SplitWords::default(),
            "I love to eat corn leaves.",
        );
    }

    #[test]
    fn issue_2763_husks() {
        assert_suggestion_result(
            "I love to eat cornhusks.",
            SplitWords::default(),
            "I love to eat corn husks.",
        );
    }

    #[test]
    fn issue_2763_singular() {
        assert_suggestion_result(
            "I would love to eat a cornleaf.",
            SplitWords::default(),
            "I would love to eat a corn leaf.",
        );
    }

    /// Tests that SplitWords is not suppressed by SpellCheck due to lower priority.
    /// When both SplitWords and SpellCheck linters fire on the same span (an unknown word that
    /// can be split into valid dictionary words), SplitWords should take precedence because its
    /// suggestion is more specific and useful.
    #[test]
    fn split_words_not_suppressed_by_spellcheck() {
        let mut group = LintGroup::new_curated(FstDictionary::curated(), Dialect::American);
        let doc = Document::new_plain_english_curated("insteadof");

        let mut named_lints = group.organized_lints(&doc);

        // Debug: print what lints we have before overlap removal
        eprintln!("=== Before overlap removal ===");
        for (key, lints) in &named_lints {
            if !lints.is_empty() {
                for l in lints {
                    eprintln!("  {key}: span={:?}, priority={}", l.span, l.priority);
                }
            }
        }

        remove_overlaps_map(&mut named_lints);

        eprintln!("=== After overlap removal ===");
        for (key, lints) in &named_lints {
            if !lints.is_empty() {
                for l in lints {
                    eprintln!("  {key}: span={:?}, priority={}", l.span, l.priority);
                }
            }
        }

        // SplitWords should still be present after overlap removal
        assert!(
            named_lints.contains_key("SplitWords"),
            "Expected SplitWords lints to be present in the result, but they were removed by overlap resolution.\n\
             Lint map keys: {:?}",
            named_lints.keys().collect::<Vec<_>>()
        );

        // SplitWords should have high priority (higher than SpellCheck's 63)
        if let Some(lints) = named_lints.get("SplitWords") {
            if let Some(lint) = lints.first() {
                assert!(
                    lint.priority > 63,
                    "SplitWords priority ({}) should be higher than SpellCheck (63)",
                    lint.priority
                );
            }
        }
    }
}

